import { pick } from 'lodash-es';

import { MapToolbarSlotProps } from '../types/toolbar.js';

type PropKey = keyof MapToolbarSlotProps;
const allowedProps: PropKey[] = ['placement', 'hidden'];

export const sanitizeProps = <P extends MapToolbarSlotProps>(
  externalProps: P,
): MapToolbarSlotProps => {
  return pick(externalProps, allowedProps);
};

/**
 * Slot for configuring the toolbar within a MapView.
 * @public
 */
export const Toolbar = (props: MapToolbarSlotProps) => null;

Toolbar.displayName = 'MapToolbar';
